import { Gender, CharacterRarity, IcharInfo, CharInfoOptions } from "../types";
import { skins } from "./skins";
import animeInfoClass, { anime } from "./anime";

export default class charInfo implements IcharInfo {
    private _name: string;
    private _alias: string[];
    private _animeInfo: animeInfoClass;
    private _gender: Gender;
    private _image: string;
    private _id: number;
    private _rarity: CharacterRarity;
    private _options?: CharInfoOptions;

    constructor(name: string, alias: string[], animeInfo: animeInfoClass, gender: Gender, image: string, id: number, rarity: CharacterRarity, options?: CharInfoOptions) {
        this._name = name;
        this._alias = alias;
        this._animeInfo = animeInfo;
        this._gender = gender;
        this._image = image;
        this._id = id;
        this._rarity = rarity;
        this._options = options;
    };
    get name() {
        return this._name;
    };
    get alias() {
        return this._alias;
    };

    get animeInfo() {
        return this._animeInfo;
    };
    get anime() {
        return this.animeInfo.name;
    };
    get anialias() {
        return this.animeInfo.alias;
    };

    get gender() {
        return this._gender;
    };
    get image() {
        return this._image;
    };
    get id() {
        return this._id;
    };
    get rarity() {
        return this._rarity;
    };
    get options() {
        return this._options ?? {};
    };

    get staticImage() {
        return this.options?.staticImage;
    };
    get tryStaticImage() {
        return this.staticImage ?? this.image;
    };

    get rarityValue() {
        return { "D": 0, "C": 1, "B": 2, "A": 3, "S": 4, "SS": 5, "EX": 6 }[this._rarity];
    };
    get rarityEmoji() {
        return {
            "EX": "<a:EXTRA:1138530846144462968>",
            "SS": "<:SSTier:869316489931546644>",
            "S": "<:STier:869316518675095552>",
            "A": "<:ATier:869316558013464627>",
            "B": "<:BTier:869316586803179571>",
            "C": "<:CTier:869316602858991657>",
            "D": "<:DTier:869316616071032843>"
        }[this._rarity];
    };

    getImage(premium: number, url: string, skin?: number, isStatic?: boolean) {
        if (premium > 2 && url) return url;
        if (skin === undefined) return isStatic ? this.tryStaticImage : this.image;
        return skins[skin].image;
    };

    // Entity info
    get species() {
        return "charInfo";
    };
    get boss() {
        return false;
    };
    get loot(): number[] {
        return [];
    };
    get floor(): number[] {
        return [];
    };
    get url() {
        return this.image;
    };
};

