export const auniq = anime.map((e) => e.name);

export const uniqueAnimeCharacters = characters.reduce((acc: { seenAnimes: Record<string, boolean>, result: charInfo[]; }, char) => {
    if (!acc.seenAnimes[char.anime]) {
        acc.seenAnimes[char.anime] = true;
        acc.result.push(char);
    };
    return acc;
}, { seenAnimes: {}, result: [] }).result.sort((a, b) => a.anime.localeCompare(b.anime));

export const charactersF = characters.filter((e) => e.gender === "F");
export const charactersM = characters.filter((e) => e.gender === "M");
export const charactersSS = characters.filter((e) => e.rarity === "SS");
export const charactersS = characters.filter((e) => e.rarity === "S");
export const charactersA = characters.filter((e) => e.rarity === "A");
export const charactersB = characters.filter((e) => e.rarity === "B");
export const charactersC = characters.filter((e) => e.rarity === "C");
export const charactersD = characters.filter((e) => e.rarity === "D");



// DEBUGGING CONTROLS
// DEBUGGING CONTROLS
// DEBUGGING CONTROLS

// Warn if ',' in name (would mess with some commands because , is being used to separate strings)
characters.forEach((e) => {
    if (e.name.includes(",") || e.alias.some((a) => a.includes(","))) throw new Error("WARNING! Character with symbol ',' in name or alias: " + e.name);
});

// Check if duplicate names
{
    // let names = characters.map((e) => e.name).sort();
    let names = characters.reduce<string[]>((acc, char) => [...acc, char.name, ...char.alias], []).sort();
    let len = names.length - 1, res = "";
    while (len--) if (names[len - 1] === names[len]) res += names[len--] + "\n";
    if (res) throw new Error("Duplicate names found: " + res);
}

// Check ID
characters.forEach((e, i) => {
    if (e.id !== i) throw new Error("WARNING! Wrong ID " + e.id + " in: " + e.name);
});

// Check if duplicate links
{
    let links = characters.map((e) => e.image).sort();
    let len = links.length - 1, res = "";
    while (len--) if (links[len - 1] === links[len]) res += links[len--] + "\n";
    if (res) throw new Error("WARNING! Duplicate links: " + res);
}

